import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type CommitData = {
  branch: string
  commits: CommitEntry[]
}

const parseGitLog = (raw: string): CommitEntry[] =>
  raw
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => {
      const [sha, author, date, ...messageParts] = line.split('|')
      return { sha, author, date, message: messageParts.join('|') }
    })

export const gitCommitSensor: SensorFactory = {
  name: 'git-commit',
  snapshotPath: 'git-commit.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    const proc = Bun.spawn(
      ['git', 'log', 'origin/main', '--format=%H|%an|%aI|%s', '-n', '20'],
      { stdout: 'pipe', stderr: 'pipe' },
    )

    const output = await new Response(proc.stdout).text()
    const exitCode = await proc.exited

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
    if (exitCode !== 0) {
      const stderr = await new Response(proc.stderr).text()
      throw new Error(`git log failed (exit ${exitCode}): ${stderr.trim()}`)
    }

    const commits = parseGitLog(output)

    return { branch: 'main', commits } satisfies CommitData
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as CommitData

    if (!previous) {
      return curr.commits.length > 0 ? curr : null
    }

    const prev = previous.data as CommitData
    const knownShas = new Set(prev.commits.map((c) => c.sha))
    const newCommits = curr.commits.filter((c) => !knownShas.has(c.sha))

    return newCommits.length > 0
      ? { branch: 'main', commits: newCommits }
      : null
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

const websocketNotifier: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return

    const wsUrl = process.env.WS_ALERT_URL
    if (!wsUrl) return

    const ws = new WebSocket(wsUrl)
    ws.addEventListener('open', () => {
      ws.send(JSON.stringify({
        type: 'git-commit-alert',
        timestamp: new Date().toISOString(),
        payload: msg.content,
      }))
      ws.close()
    })
    ws.addEventListener('error', () => {
      ws.close()
    })
  },
}

export const gitCommitGoal = createGoal((_trigger) => ({
  threads: {
    'git-commit-alert': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            (detail as SensorDeltaDetail).sensor === 'git-commit',
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'New commits were pushed to main. Summarize the changes from the git-commit sensor delta and send an alert via the message handler describing the new commits, their authors, and messages.',
            },
          },
        }),
      ],
      true,
    ),
  },
  handlers: websocketNotifier,
}))

