import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type HealthStatus = {
  statusCode: number
  ok: boolean
  timestamp: string
}

export const healthSensor: SensorFactory = {
  name: 'http-health',
  snapshotPath: 'http-health.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const url = process.env.HEALTH_ENDPOINT_URL ?? 'https://api.example.com/health'
    try {
      const response = await fetch(url, { signal })
      return {
        statusCode: response.status,
        ok: response.ok,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    } catch (error) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
      return {
        statusCode: 0,
        ok: false,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as HealthStatus

    if (!previous) {
      return curr.ok ? null : curr
    }

    const prev = previous.data as HealthStatus

    if (curr.statusCode === prev.statusCode) return null

    return {
      previousStatusCode: prev.statusCode,
      currentStatusCode: curr.statusCode,
      ok: curr.ok,
      timestamp: curr.timestamp,
    }
  },
}

