import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type AccumulatedDelta = {
  sensor: string
  delta: unknown
  timestamp: string
}

const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1000

const formatEmailBody = (deltas: AccumulatedDelta[]): string => {
  const date = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })

  if (deltas.length === 0) {
    return [
      `Daily Sensor Digest — ${date}`,
      '',
      'No sensor changes detected in the past 24 hours.',
    ].join('\n')
  }

  const grouped = Map.groupBy(deltas, (d) => d.sensor)

  const sections = [...grouped.entries()]
    .map(([sensor, entries]) => {
      const items = entries!
        .map(
          (e) => `  • ${e.timestamp}\n    ${JSON.stringify(e.delta)}`,
        )
        .join('\n')
      return `[${sensor}] (${entries!.length} change(s))\n${items}`
    })
    .join('\n\n')

  return [
    `Daily Sensor Digest — ${date}`,
    '',
    `${deltas.length} change(s) detected across ${grouped.size} sensor(s) in the past 24 hours.`,
    '',
    sections,
  ].join('\n')
}

export const emailDigestGoal = createGoal((_trigger) => {
  const deltas: AccumulatedDelta[] = []

  const pruneStaleDeltas = () => {
    const cutoff = Date.now() - TWENTY_FOUR_HOURS_MS
    while (
      deltas.length > 0 &&
      new Date(deltas[0].timestamp).getTime() < cutoff
    ) {
      deltas.shift()
    }
  }

  const handlers: DefaultHandlers = {
    [AGENT_EVENTS.message]: ({ detail }) => {
      const msg = detail as { source?: string; content?: string }
      if (msg.source !== 'proactive') return

      const smtpRelayUrl = process.env.SMTP_RELAY_URL
      if (!smtpRelayUrl) return

      pruneStaleDeltas()
      const emailBody = formatEmailBody(deltas)

      fetch(smtpRelayUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          from: process.env.DIGEST_SENDER ?? 'agent@example.com',
          to: process.env.DIGEST_RECIPIENT ?? 'team@example.com',
          subject: `Daily Sensor Digest — ${new Date().toLocaleDateString()}`,
          body: emailBody,
        }),
      }).catch(() => {
        /* non-fatal */
      })

      deltas.length = 0
    },
  }

  return {
    threads: {
      'digest-collector': bThread(
        [
          bSync({
            waitFor: ({ type, detail }) => {
              if (type !== AGENT_EVENTS.sensor_delta) return false
              const d = detail as SensorDeltaDetail
              deltas.push({
                sensor: d.sensor,
                delta: d.delta,
                timestamp: new Date().toISOString(),
              })
              return true
            },
          }),
        ],
        true,
      ),
      'digest-scheduler': bThread(
        [
          bSync({
            waitFor: ({ type }) =>
              type === AGENT_EVENTS.tick && new Date().getHours() === 8,
          }),
          bSync({
            request: {
              type: AGENT_EVENTS.task,
              detail: {
                prompt:
                  'Compose and send a daily digest email summarizing all sensor changes collected over the past 24 hours.',
              },
            },
          }),
        ],
        true,
      ),
    },
    handlers,
  }
})

import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type BackendStatus = {
  backend: 'local-gpu' | 'cloud-api'
  endpoint: string
  respondedAt: string | null
}

type BackendDelta = {
  previousBackend: string
  currentBackend: 'local-gpu' | 'cloud-api'
  switchedAt: string
}

export const inferenceBackendSensor: SensorFactory = {
  name: 'inference-backend',
  snapshotPath: 'inference-backend.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const localEndpoint = process.env.LOCAL_INFERENCE_URL ?? 'http://localhost:8080/health'

    try {
      const res = await fetch(localEndpoint, { signal, method: 'GET' })
      if (res.ok) {
        return {
          backend: 'local-gpu',
          endpoint: localEndpoint,
          respondedAt: new Date().toISOString(),
        } satisfies BackendStatus
      }
    } catch {
      // Local endpoint unreachable — fall through to cloud
    }

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    return {
      backend: 'cloud-api',
      endpoint: process.env.CLOUD_API_URL ?? 'https://api.inference.cloud/v1',
      respondedAt: null,
    } satisfies BackendStatus
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as BackendStatus

    // First run: report initial backend as delta so the goal sets the correct heartbeat
    if (!previous) return { previousBackend: 'unknown', currentBackend: curr.backend, switchedAt: new Date().toISOString() } satisfies BackendDelta

    const prev = previous.data as BackendStatus
    if (prev.backend === curr.backend) return null

    return {
      previousBackend: prev.backend,
      currentBackend: curr.backend,
      switchedAt: new Date().toISOString(),
    } satisfies BackendDelta
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'

const AGGRESSIVE_INTERVAL_MS = 300_000      // 5 minutes  — local GPU
const CONSERVATIVE_INTERVAL_MS = 7_200_000  // 2 hours    — cloud API

type BackendDelta = {
  previousBackend: string
  currentBackend: 'local-gpu' | 'cloud-api'
  switchedAt: string
}

const isBackendSwitch = (
  detail: SensorDeltaDetail,
  target: 'local-gpu' | 'cloud-api',
): detail is SensorDeltaDetail & { delta: BackendDelta } =>
  detail.sensor === 'inference-backend' &&
  detail.delta !== null &&
  (detail.delta as BackendDelta).currentBackend === target

export const costAwareHeartbeatGoal = createGoal((_trigger) => ({
  threads: {
    /**
     * When the backend switches to local GPU, crank the heartbeat up to
     * aggressive (5 min) — local inference is cheap so we poll frequently.
     */
    'switch-to-aggressive': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            isBackendSwitch(detail as SensorDeltaDetail, 'local-gpu'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.set_heartbeat,
            detail: { intervalMs: AGGRESSIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Inference backend switched to local GPU.',
                `Heartbeat increased to aggressive (${AGGRESSIVE_INTERVAL_MS / 60_000} min).`,
                'Verify GPU utilization is healthy and log the transition.',
              ].join(' '),
            },
          },
        }),
      ],
      true, // repeat — keep watching for future switches
    ),

    /**
     * When the backend falls back to cloud API, drop the heartbeat to
     * conservative (2 hr) to minimize per-request cloud costs.
     */
    'switch-to-conservative': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            isBackendSwitch(detail as SensorDeltaDetail, 'cloud-api'),
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.set_heartbeat,
            detail: { intervalMs: CONSERVATIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Inference backend fell back to cloud API.',
                `Heartbeat reduced to conservative (${CONSERVATIVE_INTERVAL_MS / 3_600_000} hr) to control costs.`,
                'Monitor for local GPU recovery and alert if cloud spend exceeds budget.',
              ].join(' '),
            },
          },
        }),
      ],
      true,
    ),
  },
}))

import { createAgentLoop } from 'src/agent/agent.loop.ts'
import { inferenceBackendSensor } from './sensor.ts'
import { costAwareHeartbeatGoal } from './goal.ts'

/**
 * Starts aggressive (5 min) — the goal will immediately downshift to
 * conservative (2 hr) on the first heartbeat if the local GPU is unreachable.
 */
const INITIAL_INTERVAL_MS = 300_000

export const createCostAwareNode = () =>
  createAgentLoop({
    proactive: {
      sensors: [inferenceBackendSensor],
      goals: [costAwareHeartbeatGoal],
      intervalMs: INITIAL_INTERVAL_MS,
    },
  })
